-- Carl Sagan (1–16)
(gen_random_uuid(), 'El cosmos es todo lo que es, todo lo que fue y todo lo que será.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'En algún lugar, algo increíble espera ser descubierto.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'La ciencia no es solo compatible con la espiritualidad; es una fuente profunda de espiritualidad.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Vivimos en una sociedad profundamente dependiente de la ciencia y la tecnología, en la que nadie sabe nada de estos temas.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'wisdom', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'La extinción es la regla. La supervivencia es la excepción.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'El cerebro humano es el objeto más complejo del universo conocido y es la única herramienta con la que podemos estudiarlo.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Cada vez que una tribu ha adoptado el pensamiento científico, la ciencia ha prosperado y la humanidad también.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'self_improvement', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'La Tierra es el único mundo conocido que alberga vida. No hay otro lugar, al menos en el futuro cercano, al que nuestra especie pudiera migrar.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Somos polvo de estrellas que contempla las estrellas.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La ciencia requiere valentía porque a menudo las verdades de la naturaleza son contrarias a nuestros prejuicios.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Quien no recuerda el pasado está condenado a repetirlo; la ciencia es la memoria colectiva de la humanidad.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'wisdom', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Un argumento es extraordinario cuando su evidencia también lo es.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'La naturaleza no miente; somos nosotros quienes la malinterpretamos.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'El universo no está obligado a ser comprensible para nosotros; es una maravilla que lo sea.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Conocerse a uno mismo es el comienzo de toda ciencia.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['self_improvement', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Preferir la ilusión a la realidad es el error más costoso que puede cometer una civilización.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),

-- Neil deGrasse Tyson (17–30)
(gen_random_uuid(), 'El universo es bajo ninguna obligación de tener sentido para ti.', 'Neil deGrasse Tyson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La exploración es lo que hacemos cuando no sabemos a dónde vamos.', 'Neil deGrasse Tyson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'El conocimiento científico es un cuerpo de afirmaciones acerca del universo de grado variable de certeza.', 'Neil deGrasse Tyson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Todos somos conectados: entre sí biológicamente, con la Tierra químicamente y con el resto del universo atómicamente.', 'Neil deGrasse Tyson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La ignorancia es una semilla de la que no puede brotar más que más ignorancia, a menos que la reguemos con curiosidad.', 'Neil deGrasse Tyson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'La astrofísica no consuela el ego; su propósito es revelar la realidad.', 'Neil deGrasse Tyson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Si el universo no tuviera belleza no la podríamos percibir; que podamos hacerlo dice algo tanto del universo como de nosotros.', 'Neil deGrasse Tyson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La ciencia es una actitud ante el conocimiento, no un conjunto de respuestas definitivas.', 'Neil deGrasse Tyson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Cuando los niños miran el cielo nocturno con asombro, en ese momento se vuelven científicos.', 'Neil deGrasse Tyson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Cuanto más del universo conocemos, más pequeños nos damos cuenta de que somos.', 'Neil deGrasse Tyson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'La razón por la que la ciencia funciona es que rechaza la verdad por autoridad y la acepta por evidencia.', 'Neil deGrasse Tyson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'wisdom', 'discipline'], true, 'science'),
(gen_random_uuid(), 'No hay mayor descubrimiento que aquel que cambia nuestra comprensión de lo que ya creíamos saber.', 'Neil deGrasse Tyson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'La muerte de las estrellas fertiliza las galaxias con los átomos que luego forman planetas y vida.', 'Neil deGrasse Tyson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Los datos son los hechos del universo; ignorarlos es elegir la oscuridad sobre la luz.', 'Neil deGrasse Tyson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'wisdom', 'discipline'], true, 'science'),

-- Richard Dawkins (31–44)
(gen_random_uuid(), 'La evolución ha sido observada. Solo que no ha sido observada mientras ocurre.', 'Richard Dawkins', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'El gen egoísta no tiene propósitos; es la selección natural la que crea la ilusión de propósito.', 'Richard Dawkins', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'La biología es el estudio de cosas complicadas que parecen diseñadas pero no lo están.', 'Richard Dawkins', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'El universo que observamos tiene precisamente las propiedades que deberíamos esperar si no hay diseño ni propósito.', 'Richard Dawkins', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'El ADN es un libro de instrucciones escrito en un alfabeto de cuatro letras que tardó miles de millones de años en escribirse.', 'Richard Dawkins', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'La selección natural es el único proceso conocido capaz de producir complejidad organizada a partir de la simplicidad.', 'Richard Dawkins', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Cada animal que ha existido es una prueba viviente de que todos sus ancestros sobrevivieron.', 'Richard Dawkins', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La genética ha revelado que todos los seres vivos son primos en algún grado.', 'Richard Dawkins', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'La ciencia ofrece una comprensión del mundo que ninguna mitología puede superar en poder explicativo.', 'Richard Dawkins', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'wisdom', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Ningún descubrimiento ha sido más liberador para la mente humana que la evolución por selección natural.', 'Richard Dawkins', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'La diversidad de la vida es el resultado de cuatro mil millones de años de talla sin artista.', 'Richard Dawkins', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Entender la evolución no es solo conocer un hecho; es ver el mundo con ojos completamente distintos.', 'Richard Dawkins', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'curiosity', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'La herencia no transmite recuerdos sino instrucciones; ese es el genio del ADN.', 'Richard Dawkins', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Rechazar la evidencia por incomodidad es el mayor obstáculo para el progreso científico.', 'Richard Dawkins', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'discipline', 'learning'], true, 'science'),

-- Jane Goodall (45–57)
(gen_random_uuid(), 'Solo cuando comprendemos podemos proteger; solo cuando protegemos podemos preservar.', 'Jane Goodall', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Los chimpancés me enseñaron que no existe una brecha tan grande entre el ser humano y el resto del reino animal.', 'Jane Goodall', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'La observación paciente es el instrumento más poderoso del naturalista.', 'Jane Goodall', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'learning', 'focus'], true, 'science'),
(gen_random_uuid(), 'Cada individuo importa, cada individuo tiene un papel que desempeñar y cada individuo marca una diferencia.', 'Jane Goodall', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'self_improvement', 'learning'], true, 'science'),
(gen_random_uuid(), 'La mayor amenaza para nuestro planeta es la creencia de que alguien más lo salvará.', 'Jane Goodall', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'self_improvement', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Los animales sienten emociones; negar eso no es ciencia, es prejuicio.', 'Jane Goodall', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'El campo es el mejor laboratorio; allí la naturaleza escribe sus propias hipótesis.', 'Jane Goodall', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'curiosity', 'discipline'], true, 'science'),
(gen_random_uuid(), 'La biodiversidad que perdemos hoy no volverá nunca; esa es la urgencia de la conservación.', 'Jane Goodall', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'self_improvement', 'learning'], true, 'science'),
(gen_random_uuid(), 'Pasé años observando chimpancés y cada día confirmaba que el comportamiento social es mucho más antiguo que la humanidad.', 'Jane Goodall', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'La empatía con otras especies es la base de una ecología responsable.', 'Jane Goodall', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'self_improvement', 'learning'], true, 'science'),
