(gen_random_uuid(), 'En la naturaleza nada existe solo; todo forma parte de una red de relaciones.', 'Rachel Carson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
