(gen_random_uuid(), 'Los contaminantes no respetan fronteras nacionales; la atmósfera es el bien común de todos.', 'Rachel Carson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'self_improvement', 'learning'], true, 'science'),
