(gen_random_uuid(), 'Esta Tierra maravillosa y magnífica que compartimos con millones de especies no es solo nuestra.', 'David Attenborough', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
