-- Marie Curie (83–95)
(gen_random_uuid(), 'Nada en la vida debe ser temido; solo debe ser comprendido. Ahora es momento de comprender más para temer menos.', 'Marie Curie', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'self_improvement'], true, 'science'),
