(gen_random_uuid(), 'Me enseñaron que el camino del progreso no es ni rápido ni fácil.', 'Marie Curie', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'self_improvement', 'wisdom'], true, 'science'),
