(gen_random_uuid(), 'La imaginación es más importante que el conocimiento; el conocimiento tiene límites pero la imaginación los rodea.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['creativity', 'wisdom', 'curiosity'], true, 'science'),
